import React, { useState, useEffect } from 'react';
import { uploadFile, getCoursesForUpload } from '../services/uploadService';
import { useAuth } from '../contexts/AuthContext';

const Upload = () => {
  const { user, isAuthenticated } = useAuth();
  
  // If not authenticated, show login message
  if (!isAuthenticated) {
    return (
      <div style={{
        maxWidth: '800px',
        margin: '0 auto',
        padding: '4rem 1rem',
        textAlign: 'center',
        minHeight: '70vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}>
        {/* ... login required message (same as before) ... */}
      </div>
    );
  }
  
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [courses, setCourses] = useState([]);
  const [loadingCourses, setLoadingCourses] = useState(true);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    course_id: '',
    type: 'notes'
  });

  useEffect(() => {
    fetchCourses();
  }, []);

  const fetchCourses = async () => {
    try {
      setLoadingCourses(true);
      const coursesData = await getCoursesForUpload();
      
      if (coursesData && Array.isArray(coursesData)) {
        setCourses(coursesData);
      } else {
        setCourses([]);
      }
    } catch (error) {
      console.error('Error fetching courses:', error);
      setCourses([]);
    } finally {
      setLoadingCourses(false);
    }
  };

  // SIMPLE FUNCTION - DIRECT ADD COURSES
  const handleAddSampleCourses = async () => {
    try {
      // Direct API call to simple endpoint
      const response = await fetch('http://localhost:5000/api/add-courses-public', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
      });
      
      const data = await response.json();
      
      if (response.ok) {
        alert(`✅ ${data.message || 'Courses added successfully!'}`);
        fetchCourses(); // Refresh courses
      } else {
        alert(`❌ ${data.error || 'Failed to add courses'}`);
      }
    } catch (error) {
      console.error('Error:', error);
      alert('❌ Network error. Check backend connection.');
    }
  };

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) {
      // Check file size (10MB limit)
      if (selectedFile.size > 10 * 1024 * 1024) {
        alert('❌ File size exceeds 10MB limit');
        e.target.value = '';
        return;
      }
      setFile(selectedFile);
    }
  };

  const handleInputChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  // ✅ FIXED: ADD 'async' KEYWORD HERE
  const handleUpload = async () => {
    // Validation
    if (!file) {
      alert('❌ Please select a file');
      return;
    }
    if (!formData.title.trim()) {
      alert('❌ Please enter title');
      return;
    }
    if (!formData.course_id) {
      alert('❌ Please select a course');
      return;
    }

    const data = new FormData();
    data.append('file', file);
    data.append('title', formData.title);
    data.append('description', formData.description);
    data.append('course_id', formData.course_id);
    data.append('type', formData.type);

    setUploading(true);

    try {
      const result = await uploadFile(data);
      
      // ✅ Show appropriate message based on backend response
      if (result.status === 'pending' || result.message?.includes('approval')) {
        alert(`✅ ${result.message}\n\n📝 Status: Under Review\n👑 Admin approval required\n⏳ Will be visible after approval`);
      } else {
        alert(`✅ ${result.message || 'Upload successful!'}`);
      }
      
      // Reset form
      setFile(null);
      setFormData({
        title: '',
        description: '',
        course_id: '',
        type: 'notes'
      });
      document.getElementById('fileInput').value = '';
      
    } catch (error) {
      alert(`❌ Upload failed: ${error.message || 'Check console for details'}`);
      console.error('Upload error:', error);
    } finally {
      setUploading(false);
    }
  };

  // ... REST OF YOUR STYLES AND JSX CODE REMAINS SAME ...
  
  return (
    <div style={styles.container}>
      {/* Header */}
      <header style={styles.header}>
        <h1 style={styles.title}>Upload Study Materials</h1>
        <p style={styles.subtitle}>
          Share your notes, PYQs, and study materials
          <br />
          <small style={{ fontSize: '0.9rem', color: '#6b7280' }}>
            🔒 Login required | 👑 Admin approval needed
          </small>
        </p>
      </header>

      {/* User Info */}
      <div style={styles.userInfo}>
        <div style={styles.userAvatar}>
          {user?.name?.charAt(0)?.toUpperCase() || 'U'}
        </div>
        <div>
          <p style={{ margin: 0, fontWeight: '600', fontSize: '1.1rem' }}>
            Uploading as: <span style={{ color: '#4f46e5' }}>{user?.name}</span>
          </p>
          <p style={{ margin: 0, fontSize: '0.9rem', color: '#6b7280' }}>
            {user?.branch} • Semester {user?.semester} • {user?.email}
          </p>
        </div>
      </div>

      {/* Warning if no courses */}
      {courses.length === 0 && !loadingCourses && (
        <div style={styles.warningBox}>
          <h3 style={styles.warningTitle}>⚠️ No Courses Found!</h3>
          <p>Add sample courses to continue uploading</p>
          <button 
            onClick={handleAddSampleCourses}
            style={styles.addButton}
          >
            ➕ Add Sample Courses
          </button>
          <p style={{ fontSize: '0.9rem', marginTop: '1rem', color: '#92400e' }}>
            This adds 6 sample courses (Data Structures, Digital Electronics, etc.)
          </p>
        </div>
      )}

      {/* File Upload Section */}
      <div style={styles.uploadBox}>
        <input
          type="file"
          id="fileInput"
          style={styles.fileInput}
          onChange={handleFileChange}
          accept=".pdf,.doc,.docx,.ppt,.pptx,.txt,.jpg,.jpeg,.png"
        />
        <label htmlFor="fileInput" style={styles.uploadLabel}>
          📁 Choose File to Upload
        </label>
        
        {file && (
          <div style={styles.fileInfo}>
            <p><strong>Selected:</strong> {file.name}</p>
            <p><strong>Size:</strong> {(file.size / 1024).toFixed(2)} KB</p>
            <p><strong>Type:</strong> {file.type}</p>
          </div>
        )}
        
        <p style={{ marginTop: '1rem', color: '#6b7280', fontSize: '0.9rem' }}>
          📎 Supported: PDF, DOC, DOCX, PPT, PPTX, TXT, JPG, JPEG, PNG
          <br />
          ⚠️ Maximum file size: 10MB
        </p>
      </div>

      {/* Upload Form */}
      <div style={styles.form}>
        {/* Title */}
        <div style={styles.formGroup}>
          <label style={styles.label}>Title <span style={{ color: '#ef4444' }}>*</span></label>
          <input
            type="text"
            name="title"
            placeholder="Enter descriptive title"
            value={formData.title}
            onChange={handleInputChange}
            style={styles.input}
            disabled={courses.length === 0}
          />
        </div>

        {/* Description */}
        <div style={styles.formGroup}>
          <label style={styles.label}>Description</label>
          <textarea
            name="description"
            placeholder="Add description about the material (optional)"
            value={formData.description}
            onChange={handleInputChange}
            style={styles.textarea}
            disabled={courses.length === 0}
          />
        </div>

        {/* Course Dropdown */}
        <div style={styles.formGroup}>
          <label style={styles.label}>Course <span style={{ color: '#ef4444' }}>*</span></label>
          {loadingCourses ? (
            <div style={{ 
              ...styles.select, 
              background: '#f3f4f6', 
              color: '#9ca3af', 
              textAlign: 'center',
              fontStyle: 'italic'
            }}>
              ⏳ Loading courses...
            </div>
          ) : courses.length === 0 ? (
            <div style={{ 
              ...styles.select, 
              background: '#fee2e2', 
              color: '#dc2626', 
              textAlign: 'center'
            }}>
              ⚠️ No courses available
            </div>
          ) : (
            <select
              name="course_id"
              value={formData.course_id}
              onChange={handleInputChange}
              style={styles.select}
              required
            >
              <option value="">Select a course</option>
              {courses.map(course => (
                <option key={course.id} value={course.id}>
                  {course.name} ({course.branch} - Sem {course.semester})
                </option>
              ))}
            </select>
          )}
        </div>

        {/* Type */}
        <div style={styles.formGroup}>
          <label style={styles.label}>Type <span style={{ color: '#ef4444' }}>*</span></label>
          <select
            name="type"
            value={formData.type}
            onChange={handleInputChange}
            style={styles.select}
            disabled={courses.length === 0}
          >
            <option value="notes">📄 Notes</option>
            <option value="pyq">📝 Previous Year Questions (PYQ)</option>
            <option value="syllabus">📋 Syllabus</option>
          </select>
        </div>

        {/* Upload Button */}
        <button
          onClick={handleUpload}
          disabled={uploading || courses.length === 0 || !file || !formData.title || !formData.course_id}
          style={{
            ...styles.uploadButton,
            background: uploading || courses.length === 0 || !file || !formData.title || !formData.course_id
              ? '#9ca3af'
              : 'linear-gradient(90deg, #10b981, #059669)'
          }}
        >
          {uploading ? '⏳ Uploading...' : '📤 Upload Material'}
        </button>

        <div style={{ 
          marginTop: '1rem', 
          padding: '1rem',
          background: '#f3f4f6',
          borderRadius: '8px',
          fontSize: '0.9rem',
          color: '#6b7280'
        }}>
          <p style={{ margin: 0, display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <span>⚠️</span>
            <span>
              <strong>Note:</strong> All uploads require admin approval. 
              Your file will be visible after review.
            </span>
          </p>
        </div>
      </div>
    </div>
  );
};

// ... REST OF YOUR STYLES OBJECT REMAINS SAME ...

export default Upload;
